code = """import json

# Load UC patent publication numbers from the saved result
uc_patents_file = 'file_storage/functions.query_db:5.json'
with open(uc_patents_file, 'r') as f:
    uc_patents = json.load(f)

# Extract UC publication numbers
uc_pub_numbers = set()
for patent in uc_patents:
    patents_info = patent['Patents_info']
    import re
    pub_match = re.search(r'(?:pub|publication)(?:\s+number)?\s+([A-Z]{2}-[\dA-Z-]+)', patents_info)
    if pub_match:
        uc_pub_numbers.add(pub_match.group(1))

print('__RESULT__:')
print(json.dumps({
    'uc_pub_numbers_count': len(uc_pub_numbers),
    'sample_numbers': list(uc_pub_numbers)[:5]
}))"""

